const CORS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

const MAX_PAYLOAD = 64 * 1024; // 64 KB

// Embedded game HTML (generated by build.js — do not edit manually)
const GAME_HTML = "<!DOCTYPE html>\n<html lang=\"ru\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>La Fournée — Пекарня-кофейня</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Nunito:wght@400;500;600;700&display=swap\" rel=\"stylesheet\">\n<style>\n:root{\n  --espresso:#1C0A00;--cream:#F5E6C8;--caramel:#C8873A;--sage:#4A7C59;--latte:#E8C4A0;\n  --latte2:#d4a87a;--shadow:rgba(28,10,0,.15);--red:#c0392b;\n}\n*{box-sizing:border-box;margin:0;padding:0}\nhtml,body{height:100%;overflow:hidden}\nbody{display:flex;flex-direction:column;font-family:'Nunito',sans-serif;background:var(--cream);color:var(--espresso);min-width:1024px}\n\n/* HEADER */\n#hdr{flex-shrink:0;background:var(--espresso);color:var(--cream);padding:9px 20px;display:flex;align-items:center;justify-content:space-between;box-shadow:0 2px 8px rgba(0,0,0,.35)}\n.brand{font-family:'Playfair Display',serif;font-size:21px;font-weight:700;letter-spacing:1px}\n.brand em{color:var(--caramel);font-style:normal}\n#hdr-mid{display:flex;flex-direction:column;align-items:center;gap:1px}\n#hdr-day{font-size:12px;opacity:.75;font-weight:600}\n#hdr-wx{font-size:12px;color:var(--caramel);font-weight:600}\n#hdr-r{display:flex;flex-direction:column;align-items:flex-end;gap:2px}\n#hdr-money{font-size:19px;font-weight:700;color:var(--caramel)}\n.rep-row{display:flex;align-items:center;gap:6px;font-size:11px;opacity:.8}\n#rep-bar{width:80px;height:5px;background:rgba(255,255,255,.18);border-radius:3px}\n#rep-fill{height:100%;background:var(--sage);border-radius:3px;transition:width .5s}\n\n/* TOOLBAR */\n#toolbar{flex-shrink:0;background:var(--latte);border-bottom:2px solid var(--caramel);display:flex;align-items:center;justify-content:space-between;padding:6px 16px;gap:8px}\n.tb-l{display:flex;gap:7px;align-items:center}\n.tb-btn{padding:6px 13px;border:1.5px solid rgba(200,135,58,.35);border-radius:8px;cursor:pointer;font-family:'Nunito',sans-serif;font-weight:600;font-size:12px;background:var(--cream);color:var(--espresso);transition:all .18s}\n.tb-btn:hover{background:var(--caramel);color:#fff;border-color:var(--caramel)}\n#tb-r{display:flex;gap:7px;align-items:center}\n\n/* BUTTONS */\n.btn{padding:8px 15px;border:none;border-radius:8px;cursor:pointer;font-family:'Nunito',sans-serif;font-weight:700;font-size:13px;transition:all .18s}\n.btn-p{background:var(--caramel);color:#fff}\n.btn-p:hover{background:#a66d28;transform:translateY(-1px)}\n.btn-s{background:var(--sage);color:#fff}\n.btn-s:hover{background:#3a6447;transform:translateY(-1px)}\n.btn-o{background:transparent;color:var(--caramel);border:2px solid var(--caramel)}\n.btn-o:hover{background:var(--caramel);color:#fff}\n.btn:active{transform:translateY(0)!important}\n.panel{background:var(--latte);border-radius:13px;padding:13px;box-shadow:0 2px 8px var(--shadow);overflow-y:auto}\n.panel h3{font-family:'Playfair Display',serif;font-size:14px;margin-bottom:10px;border-bottom:2px solid var(--caramel);padding-bottom:5px}\n\n/* CENTER PANEL */\n#center-panel{flex-shrink:0}\n\n/* DAY CARD */\n#day-card{background:var(--espresso);color:var(--cream);padding:10px 20px 14px;border-bottom:3px solid var(--caramel)}\n#cafe-scene{background:linear-gradient(180deg,#3a2418 0%,#2c1810 70%,#241208 100%);border-radius:11px;padding:10px 14px;margin-bottom:10px;position:relative;overflow:hidden;border:1px solid rgba(200,135,58,.3)}\n#cafe-decor-row{position:absolute;top:6px;right:10px;font-size:14px;display:flex;gap:6px;opacity:.85}\n#cafe-counter{display:flex;align-items:center;gap:12px;min-height:46px}\n#cafe-counter .counter-icon{font-size:30px}\n#cafe-active-cust{flex:1;font-size:13px;font-weight:600}\n#cafe-seats{display:flex;gap:8px;margin-top:8px;padding-top:8px;border-top:1px dashed rgba(245,230,200,.18);flex-wrap:wrap}\n.seat-slot{width:34px;height:34px;border-radius:8px;background:rgba(245,230,200,.07);display:flex;align-items:center;justify-content:center;font-size:18px;position:relative}\n.seat-slot.occupied{background:rgba(200,135,58,.18)}\n.seat-slot .seat-bar{position:absolute;bottom:2px;left:3px;right:3px;height:2px;background:rgba(245,230,200,.2);border-radius:2px;overflow:hidden}\n.seat-slot .seat-bar::after{content:'';position:absolute;left:0;top:0;height:100%;width:var(--p,0%);background:var(--sage)}\n#time-row{display:flex;align-items:center;gap:8px;margin-bottom:8px}\n#time-lbl{font-size:15px;font-weight:700;color:var(--caramel);min-width:44px}\n#timebar-wrap{flex:1;height:7px;background:rgba(255,255,255,.15);border-radius:4px;overflow:hidden}\n#day-timebar{height:100%;background:var(--caramel);border-radius:4px;transition:width .5s linear}\n.time-cap{font-size:11px;opacity:.55}\n#cust-row{display:flex;align-items:center;gap:10px;margin-bottom:7px;flex-wrap:wrap}\n#eating-info{font-size:11px;color:rgba(245,230,200,.55)}\n#queue-display{display:flex;gap:5px;align-items:flex-end}\n.q-av{text-align:center;cursor:default}\n.q-av .qf{font-size:16px;line-height:1}\n.q-av .qb{width:20px;height:3px;background:rgba(255,255,255,.18);border-radius:2px;margin-top:2px;position:relative;overflow:hidden}\n.q-av .qb::after{content:'';position:absolute;left:0;top:0;height:100%;width:var(--p,100%);background:var(--sage);border-radius:2px}\n.q-av.angry .qb::after{background:var(--red)}\n#sell-row{display:flex;gap:7px;align-items:center;flex-wrap:wrap}\n#day-log-line{font-size:11px;color:rgba(245,230,200,.65);margin-top:5px;min-height:15px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n#day-earned-hdr{font-size:13px;font-weight:700;color:var(--caramel);margin-left:auto}\n\n/* EVENING CARD */\n#evening-card{background:var(--latte);padding:14px 20px;border-bottom:3px solid var(--caramel);max-height:260px;overflow-y:auto}\n.ev-stats{display:flex;gap:16px;margin-bottom:10px}\n.ev-stat{background:var(--cream);border-radius:10px;padding:8px 16px;text-align:center;flex:1}\n.ev-stat .ev-v{font-family:'Playfair Display',serif;font-size:24px;color:var(--caramel);font-weight:700}\n.ev-stat .ev-l{font-size:10px;color:rgba(28,10,0,.5);text-transform:uppercase;letter-spacing:.4px}\n.ev-goals{display:flex;flex-direction:column;gap:3px;margin-bottom:8px}\n.ev-goal{display:flex;align-items:center;gap:7px;font-size:12px}\n.ev-goal.done{color:var(--sage)}\n.ev-goal:not(.done){opacity:.55}\n.ev-bonus{font-size:14px;font-weight:700;color:var(--sage);margin-bottom:8px}\n.ev-leftovers{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:8px;font-size:12px}\n.ev-lft-tag{background:rgba(200,135,58,.14);border:1px solid rgba(200,135,58,.4);color:var(--caramel);border-radius:6px;padding:2px 8px;font-size:11px;font-weight:700}\n.ev-unlock{background:linear-gradient(135deg,var(--sage),#2d5c3f);border-radius:10px;padding:10px 14px;color:#fff;font-size:13px;margin-bottom:8px;animation:upop .5s ease}\n@keyframes upop{from{transform:scale(.85);opacity:0}to{transform:scale(1);opacity:1}}\n\n/* WORKBENCH */\n#workbench{flex:1;min-height:0;display:grid;grid-template-columns:195px 1fr 250px;gap:9px;padding:9px 12px}\n\n/* INGREDIENT LIST */\n.ing-item{display:flex;align-items:center;gap:7px;padding:6px 9px;margin-bottom:4px;background:var(--cream);border-radius:9px;cursor:pointer;border:1.5px solid transparent;transition:all .16s;user-select:none}\n.ing-item:hover{border-color:var(--caramel);transform:translateX(2px)}\n.ing-item span{font-size:12px;font-weight:600}\n\n/* TABLE / DROP ZONE */\n#drop-zone{min-height:120px;border:2px dashed var(--caramel);border-radius:11px;padding:9px;margin-bottom:8px;display:flex;flex-wrap:wrap;gap:7px;align-content:flex-start;transition:background .18s;position:relative}\n#drop-zone.over{background:rgba(200,135,58,.1)}\n.di{display:flex;flex-direction:column;align-items:center;gap:2px;padding:7px 9px;background:var(--cream);border-radius:9px;border:1.5px solid var(--caramel);cursor:pointer;transition:all .16s;min-width:58px}\n.di:hover{background:var(--caramel);color:#fff}\n.di span{font-size:10px;font-weight:600}\n#drop-hint{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:rgba(28,10,0,.3);font-size:12px;pointer-events:none}\n#rec-match{padding:8px;background:rgba(74,124,89,.1);border-radius:9px;margin-bottom:8px;min-height:46px}\n.rm-label{font-size:10px;font-weight:700;color:var(--sage);text-transform:uppercase;letter-spacing:.5px;margin-bottom:4px}\n.rm-card{display:flex;align-items:center;gap:7px;padding:6px 9px;background:var(--sage);color:#fff;border-radius:7px;font-size:12px;font-weight:600}\n#exp-hint{font-size:11px;color:var(--sage);background:rgba(74,124,89,.1);border-radius:7px;padding:5px 9px;margin-bottom:7px;display:none}\n\n/* SHOWCASE */\n.sc-item{display:flex;align-items:center;gap:6px;padding:6px 8px;background:var(--cream);border-radius:8px;margin-bottom:4px}\n.sc-item .iname{flex:1;font-size:11px;font-weight:600}\n.sc-item .iprice{font-size:10px;color:var(--caramel);font-weight:700}\n.qty{display:flex;align-items:center;gap:2px}\n.qb{width:19px;height:19px;border:1.5px solid var(--caramel);background:none;border-radius:4px;cursor:pointer;font-size:12px;color:var(--caramel);line-height:1}\n.qb:hover{background:var(--caramel);color:#fff}\n.qv{font-size:11px;font-weight:700;min-width:16px;text-align:center}\n#budget-bar{background:var(--cream);border-radius:7px;padding:7px;margin-bottom:8px;font-size:11px}\n#bprog{height:6px;background:rgba(28,10,0,.1);border-radius:3px;margin-top:3px}\n#bfill{height:100%;background:var(--caramel);border-radius:3px;transition:width .3s}\n.goal-item{display:flex;align-items:center;gap:6px;padding:5px 7px;background:var(--cream);border-radius:7px;margin-bottom:3px}\n.goal-chk{font-size:13px;flex-shrink:0;width:16px;text-align:center}\n.goal-desc{flex:1;font-size:11px;font-weight:600}\n.goal-rwd{font-size:10px;font-weight:700;color:var(--caramel)}\n.demand-row{display:flex;flex-wrap:wrap;gap:3px;margin-top:4px}\n.demand-tag{background:rgba(200,135,58,.14);border:1px solid rgba(200,135,58,.4);color:var(--caramel);border-radius:5px;padding:2px 6px;font-size:10px;font-weight:700}\n.rm-label{font-size:10px;font-weight:700;color:var(--sage);text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px}\n.section-sep{border:none;border-top:1px solid rgba(200,135,58,.25);margin:8px 0}\n\n/* RECIPE BOOK MODAL */\n#rb-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:600;align-items:center;justify-content:center}\n#rb-overlay.active{display:flex}\n#rb-modal{background:var(--cream);border-radius:18px;padding:22px;width:700px;max-height:82vh;overflow-y:auto;box-shadow:0 8px 40px rgba(0,0,0,.35)}\n#rb-modal h2{font-family:'Playfair Display',serif;font-size:22px;margin-bottom:3px}\n#rb-modal .sub{font-size:12px;color:rgba(28,10,0,.5);margin-bottom:14px}\n.rb-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:8px}\n.rb-card{background:var(--latte);border-radius:11px;padding:10px;display:flex;flex-direction:column;align-items:center;gap:5px;border:2px solid transparent;transition:all .18s}\n.rb-card.unlocked{border-color:rgba(200,135,58,.4)}\n.rb-card.locked{opacity:.4;filter:grayscale(.6)}\n.rb-card .rc-name{font-size:11px;font-weight:700;text-align:center}\n.rb-card .rc-price{font-size:12px;color:var(--caramel);font-weight:700}\n.rb-card .rc-ings{font-size:9px;color:rgba(28,10,0,.5);text-align:center}\n.rb-section{font-family:'Playfair Display',serif;font-size:13px;margin:10px 0 5px;color:var(--caramel)}\n\n/* DECOR MODAL */\n#decor-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:600;align-items:center;justify-content:center}\n#decor-overlay.active{display:flex}\n#decor-modal{background:var(--cream);border-radius:18px;padding:22px;width:820px;max-height:85vh;overflow-y:auto;box-shadow:0 8px 40px rgba(0,0,0,.35)}\n#decor-modal h2{font-family:'Playfair Display',serif;font-size:22px;margin-bottom:14px}\n#decor-layout{display:grid;grid-template-columns:1fr 270px;gap:16px;align-items:start}\n#dc{display:block;width:100%;border-radius:11px;background:#e8d8b8}\n.di-item{background:var(--latte);border-radius:9px;padding:9px;margin-bottom:7px;display:flex;align-items:center;gap:8px}\n.di-item .dico{font-size:20px;flex-shrink:0}\n.di-item .dinfo{flex:1}\n.di-item .dtitle{font-size:12px;font-weight:700}\n.di-item .ddesc{font-size:10px;color:rgba(28,10,0,.5)}\n.di-item .dprice{color:var(--caramel);font-weight:700;font-size:12px}\n.owned-badge{display:inline-block;padding:2px 7px;background:var(--sage);color:#fff;border-radius:6px;font-size:10px;font-weight:700}\n\n/* NOTIFICATIONS */\n#nw{position:fixed;top:68px;right:16px;z-index:900;display:flex;flex-direction:column;gap:6px;pointer-events:none}\n.notif{padding:8px 14px;border-radius:9px;font-size:12px;font-weight:600;animation:nin .3s ease;box-shadow:0 4px 14px rgba(0,0,0,.2)}\n@keyframes nin{from{transform:translateX(80px);opacity:0}to{transform:translateX(0);opacity:1}}\n.notif.g{background:var(--sage);color:#fff}\n.notif.b{background:var(--red);color:#fff}\n.notif.i{background:var(--espresso);color:var(--cream)}\n.notif.out{animation:nout .3s ease forwards}\n@keyframes nout{to{transform:translateX(80px);opacity:0}}\n\n/* Steam */\n@keyframes steam{0%,100%{opacity:0;transform:translateY(0) scaleX(1)}50%{opacity:.55;transform:translateY(-10px) scaleX(1.3)}}\n.sp{animation:steam 2s ease-in-out infinite}\n.sp:nth-child(2){animation-delay:.35s}\n.sp:nth-child(3){animation-delay:.7s}\n::-webkit-scrollbar{width:4px}\n::-webkit-scrollbar-thumb{background:var(--latte2);border-radius:3px}\n</style>\n</head>\n<body>\n\n<div id=\"hdr\">\n  <div class=\"brand\">☕ La <em>Fournée</em></div>\n  <div id=\"hdr-mid\">\n    <div id=\"hdr-day\">День 1 · Понедельник</div>\n    <div id=\"hdr-wx\">🌤 Солнечно</div>\n  </div>\n  <div id=\"hdr-r\">\n    <div id=\"hdr-money\">500 ₽</div>\n    <div class=\"rep-row\">Репутация: <span id=\"rep-pct\">50%</span><div id=\"rep-bar\"><div id=\"rep-fill\" style=\"width:50%\"></div></div></div>\n  </div>\n</div>\n\n<div id=\"toolbar\">\n  <div class=\"tb-l\">\n    <button class=\"tb-btn\" onclick=\"openRB()\">📖 Рецепты</button>\n    <button class=\"tb-btn\" onclick=\"openDecor()\">🏠 Интерьер</button>\n  </div>\n  <div id=\"tb-r\"></div>\n</div>\n\n<div id=\"center-panel\">\n  <!-- Day card -->\n  <div id=\"day-card\" style=\"display:none\">\n    <div id=\"time-row\">\n      <span class=\"time-cap\">08:00</span>\n      <div id=\"timebar-wrap\"><div id=\"day-timebar\" style=\"width:0%\"></div></div>\n      <span id=\"time-lbl\">08:00</span>\n      <span class=\"time-cap\">16:00</span>\n      <span id=\"day-earned-hdr\">0 ₽</span>\n    </div>\n    <div id=\"cafe-scene\">\n      <div id=\"cafe-decor-row\"></div>\n      <div id=\"cafe-counter\">\n        <div class=\"counter-icon\">☕</div>\n        <div id=\"cafe-active-cust\">Ждём первых гостей...</div>\n      </div>\n      <div id=\"cafe-seats\"></div>\n    </div>\n    <div id=\"cust-row\">\n      <div id=\"eating-info\"></div>\n      <span class=\"time-cap\" id=\"queue-lbl\" style=\"display:none\">Очередь:</span>\n      <div id=\"queue-display\"></div>\n    </div>\n    <div id=\"sell-row\">\n      <button class=\"btn btn-s\" style=\"padding:7px 18px\" onclick=\"sellToCust()\">✓ Обслужить</button>\n      <button class=\"btn\" style=\"background:var(--espresso);color:var(--cream);padding:7px 18px\" onclick=\"rejectCust()\">✗ Нет в наличии</button>\n      <button class=\"btn btn-o\" id=\"btn-auto\" style=\"padding:7px 14px;font-size:12px\" onclick=\"toggleAuto()\">🤖 Авто: ВЫКЛ</button>\n    </div>\n    <div id=\"day-log-line\"></div>\n  </div>\n  <!-- Evening card -->\n  <div id=\"evening-card\" style=\"display:none\"></div>\n</div>\n\n<div id=\"workbench\">\n  <!-- Ingredients -->\n  <div class=\"panel\">\n    <h3>Ингредиенты</h3>\n    <div id=\"ing-list\"></div>\n  </div>\n  <!-- Workbench table -->\n  <div class=\"panel\">\n    <h3>Рабочий стол</h3>\n    <div id=\"drop-zone\"><div id=\"drop-hint\">Нажмите на ингредиент или перетащите сюда</div></div>\n    <div id=\"exp-hint\">✨ Неизвестная комбинация — попробуйте эксперимент!</div>\n    <div id=\"rec-match\"><div class=\"rm-label\">Распознан рецепт</div><div id=\"rm-res\" style=\"color:rgba(28,10,0,.4);font-size:12px\">Пока ничего...</div></div>\n    <div style=\"display:flex;gap:6px;flex-wrap:wrap\">\n      <button class=\"btn btn-p\" style=\"font-size:12px;padding:7px 14px\" onclick=\"addToShowcase()\">+ В витрину</button>\n      <button class=\"btn btn-s\" style=\"font-size:12px;padding:7px 14px\" onclick=\"tryExp()\">🧪 Эксперимент</button>\n      <button class=\"btn btn-o\" style=\"font-size:12px;padding:7px 12px\" onclick=\"clearTable()\">✕ Очистить</button>\n    </div>\n  </div>\n  <!-- Showcase -->\n  <div class=\"panel\" id=\"sc-col\">\n    <h3>Витрина</h3>\n    <div id=\"budget-bar\">\n      <div>Бюджет: <strong id=\"bleft\">500 ₽</strong></div>\n      <div id=\"bprog\"><div id=\"bfill\" style=\"width:0%\"></div></div>\n    </div>\n    <div id=\"sc-list\"></div>\n    <div id=\"sc-empty\" style=\"color:rgba(28,10,0,.4);font-size:12px;text-align:center;padding:12px\">Витрина пуста</div>\n    <div style=\"font-size:10px;color:rgba(28,10,0,.4);margin-bottom:6px\">Позиций: <span id=\"cap-used\">0</span>/20</div>\n    <div id=\"open-btn-wrap\"><button class=\"btn btn-p\" style=\"width:100%;font-size:13px\" onclick=\"openBakery()\">Открыть кофейню ☀️</button></div>\n    <hr class=\"section-sep\">\n    <div id=\"goals-sec\" style=\"display:none\">\n      <div class=\"rm-label\">🎯 Цели дня</div>\n      <div id=\"goals-list\"></div>\n    </div>\n    <div id=\"demand-sec\" style=\"display:none\">\n      <div class=\"rm-label\">📋 Вчера спрашивали</div>\n      <div id=\"demand-list\" class=\"demand-row\"></div>\n    </div>\n  </div>\n</div>\n\n<!-- RECIPE BOOK MODAL -->\n<div id=\"rb-overlay\" onclick=\"if(event.target===this)closeRB()\">\n  <div id=\"rb-modal\">\n    <h2>📖 Книга рецептов</h2>\n    <div class=\"sub\">Нажмите на ингредиент или перетащите на рабочий стол</div>\n    <div class=\"rb-section\">Выпечка</div>\n    <div class=\"rb-grid\" id=\"rb-bakery\"></div>\n    <div class=\"rb-section\">Напитки</div>\n    <div class=\"rb-grid\" id=\"rb-drinks\"></div>\n    <div class=\"rb-section\" id=\"rb-special-hdr\" style=\"display:none\">Особые</div>\n    <div class=\"rb-grid\" id=\"rb-special\"></div>\n    <div style=\"margin-top:16px;text-align:right\">\n      <button class=\"btn btn-o\" onclick=\"closeRB()\">Закрыть</button>\n    </div>\n  </div>\n</div>\n\n<!-- DECOR MODAL -->\n<div id=\"decor-overlay\" onclick=\"if(event.target===this)closeDecor()\">\n  <div id=\"decor-modal\">\n    <h2>🏠 Интерьер кофейни</h2>\n    <div id=\"decor-layout\">\n      <canvas id=\"dc\" width=\"500\" height=\"280\"></canvas>\n      <div>\n        <div style=\"font-size:12px;color:rgba(28,10,0,.5);margin-bottom:10px\">Уютный интерьер привлекает больше гостей и повышает настроение клиентов</div>\n        <div id=\"decor-list\"></div>\n      </div>\n    </div>\n    <div style=\"margin-top:14px;text-align:right\">\n      <button class=\"btn btn-o\" onclick=\"closeDecor()\">Закрыть</button>\n    </div>\n  </div>\n</div>\n\n<div id=\"nw\"></div>\n\n<script>\n// ─── DATA ─────────────────────────────────────────────────\nconst DAYS=['Понедельник','Вторник','Среда','Четверг','Пятница','Суббота','Воскресенье'];\nconst WEATHERS=[\n  {name:'Солнечно',icon:'🌤'},{name:'Облачно',icon:'☁️'},{name:'Дождь',icon:'🌧'},\n  {name:'Жара',icon:'☀️'},{name:'Ветер',icon:'💨'}\n];\n\nconst INGS=[\n  {id:'flour',name:'Мука'},{id:'butter',name:'Масло'},{id:'milk',name:'Молоко'},\n  {id:'sugar',name:'Сахар'},{id:'cinnamon',name:'Корица'},{id:'eggs',name:'Яйца'},\n  {id:'blueberry',name:'Черника'},{id:'water',name:'Вода'},{id:'yeast',name:'Дрожжи'},\n  {id:'chocolate',name:'Шоколад'},{id:'coffee',name:'Кофе'},{id:'foam',name:'Пена'},\n  {id:'lemon',name:'Лимон'},{id:'cream',name:'Сливки'},{id:'vanilla',name:'Ваниль'},\n  {id:'honey',name:'Мёд'},{id:'matcha',name:'Матча'},\n];\n\nconst RECIPES=[\n  // ─ Выпечка (unlocked) ─\n  {id:'croissant',name:'Круассан',price:80,ings:['flour','butter','milk'],cat:'bakery'},\n  {id:'cinnamon_bun',name:'Булочка с корицей',price:65,ings:['flour','sugar','cinnamon'],cat:'bakery'},\n  {id:'muffin',name:'Маффин черничный',price:90,ings:['flour','eggs','blueberry'],cat:'bakery'},\n  {id:'baguette',name:'Багет',price:70,ings:['flour','water','yeast'],cat:'bakery'},\n  {id:'eclair',name:'Эклер',price:120,ings:['flour','eggs','chocolate'],cat:'bakery'},\n  // ─ Напитки (unlocked) ─\n  {id:'espresso',name:'Эспрессо',price:90,ings:['coffee','water'],cat:'drink'},\n  {id:'cappuccino',name:'Капучино',price:140,ings:['coffee','milk','foam'],cat:'drink'},\n  {id:'latte',name:'Латте',price:150,ings:['coffee','milk','cream'],cat:'drink'},\n  {id:'lemonade',name:'Лимонад',price:80,ings:['lemon','water','sugar'],cat:'drink'},\n  // ─ Выпечка (locked) ─\n  {id:'almond_croissant',name:'Круассан с миндалём',price:115,ings:['flour','butter','cream'],cat:'bakery',locked:true},\n  {id:'honey_cake',name:'Медовик',price:210,ings:['flour','eggs','honey'],cat:'bakery',locked:true},\n  {id:'chocolate_croissant',name:'Шоколадный круассан',price:105,ings:['flour','butter','chocolate'],cat:'bakery',locked:true},\n  {id:'waffle',name:'Вафля бельгийская',price:95,ings:['flour','eggs','butter'],cat:'bakery',locked:true},\n  {id:'tart',name:'Тарт с ягодами',price:130,ings:['flour','butter','sugar'],cat:'bakery',locked:true},\n  {id:'cheesecake',name:'Чизкейк',price:180,ings:['flour','cream','eggs'],cat:'bakery',locked:true},\n  // ─ Напитки (locked) ─\n  {id:'matcha_latte',name:'Матча латте',price:175,ings:['matcha','milk','foam'],cat:'drink',locked:true},\n  {id:'honey_latte',name:'Медовый латте',price:160,ings:['coffee','milk','honey'],cat:'drink',locked:true},\n  {id:'hot_chocolate',name:'Горячий шоколад',price:130,ings:['chocolate','milk','foam'],cat:'drink',locked:true},\n  {id:'vanilla_latte',name:'Ванильный латте',price:165,ings:['coffee','cream','vanilla'],cat:'drink',locked:true},\n  // ─ Особые (locked) ─\n  {id:'recipe_of_day',name:'Авторский рецепт',price:140,ings:[],cat:'special',locked:true},\n  {id:'breakfast',name:'Меню завтрака',price:260,ings:['flour','eggs','butter'],cat:'special',locked:true},\n];\n\nconst CTYPES=[\n  {id:'student',name:'Студент',emoji:'🧑‍🎓',speed:1.2,patience:15,prefs:['espresso','baguette','cinnamon_bun'],tip:.05},\n  {id:'bizlady',name:'Бизнес-леди',emoji:'👩‍💼',speed:1.8,patience:12,prefs:['latte','cappuccino','croissant','vanilla_latte'],tip:.2},\n  {id:'tourist',name:'Турист',emoji:'🧳',speed:1.0,patience:25,prefs:null,tip:.15},\n  {id:'hipster',name:'Хипстер',emoji:'🧔',speed:1.1,patience:20,prefs:['matcha_latte','eclair','recipe_of_day','honey_latte'],tip:.1},\n  {id:'granny',name:'Пенсионерка',emoji:'👵',speed:0.6,patience:30,prefs:['lemonade','baguette','cinnamon_bun','honey_cake'],tip:0},\n  {id:'mom',name:'Мама с коляской',emoji:'👩',speed:0.8,patience:22,prefs:['latte','croissant','muffin','hot_chocolate'],tip:.05},\n];\n\nconst DECORS=[\n  {id:'table',name:'Уютный столик',desc:'+5% туристов',price:300,icon:'🪑'},\n  {id:'painting',name:'Картина',desc:'+10% хипстеров',price:500,icon:'🖼'},\n  {id:'plant',name:'Растение',desc:'+2% репутация/день',price:200,icon:'🌿'},\n  {id:'lighting',name:'Тёплый свет',desc:'+5% все клиенты',price:800,icon:'💡'},\n  {id:'menu_board',name:'Меловая доска',desc:'+8% продажи',price:400,icon:'📋'},\n  {id:'jazz',name:'Живая музыка',desc:'+30% терпение',price:1200,icon:'🎵'},\n];\n\nconst GOAL_POOL=[\n  {id:'earn300',desc:'Заработать 300₽',check:()=>S.dayStats.earned>=300,reward:60},\n  {id:'earn600',desc:'Заработать 600₽',check:()=>S.dayStats.earned>=600,reward:120},\n  {id:'earn1000',desc:'Заработать 1000₽',check:()=>S.dayStats.earned>=1000,reward:200},\n  {id:'sell5',desc:'Продать 5 блюд',check:()=>Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0)>=5,reward:60},\n  {id:'sell10',desc:'Продать 10 блюд',check:()=>Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0)>=10,reward:120},\n  {id:'nounhappy',desc:'Ни одного недовольного',check:()=>S.dayStats.unhappy===0,reward:100},\n  {id:'rep70',desc:'Репутация выше 70%',check:()=>S.rep>=70,reward:80},\n  {id:'variety',desc:'Продать 3 вида блюд',check:()=>Object.keys(S.dayStats.sold).filter(k=>S.dayStats.sold[k]>0).length>=3,reward:70},\n  {id:'coffee3',desc:'Продать 3 кофейных напитка',check:()=>['espresso','cappuccino','latte','matcha_latte','honey_latte','vanilla_latte'].reduce((a,id)=>a+(S.dayStats.sold[id]||0),0)>=3,reward:60},\n  {id:'hipster',desc:'Обслужить хипстера',check:()=>(S.dayStats.byType||{}).hipster>=1,reward:40},\n  {id:'tourist',desc:'Обслужить туриста',check:()=>(S.dayStats.byType||{}).tourist>=1,reward:50},\n  {id:'exp1',desc:'Провести эксперимент',check:()=>S.dayStats.exp>=1,reward:30},\n  {id:'sell15',desc:'Продать 15 блюд',check:()=>Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0)>=15,reward:180},\n  {id:'granny',desc:'Обслужить пенсионерку',check:()=>(S.dayStats.byType||{}).granny>=1,reward:35},\n  {id:'bake3',desc:'Испечь 3 вида выпечки',check:()=>Object.keys(S.dayStats.sold).filter(k=>{const r=RECIPES.find(x=>x.id===k);return r&&r.cat==='bakery'&&S.dayStats.sold[k]>0}).length>=3,reward:70},\n  {id:'earn1500',desc:'Заработать 1500₽',check:()=>S.dayStats.earned>=1500,reward:300},\n];\n\n// ─── STATE ─────────────────────────────────────────────────\nlet S={\n  day:1,money:500,rep:50,weather:WEATHERS[0],\n  showcase:{},table:[],dayStats:{earned:0,sold:{},unhappy:0,exp:0,byType:{},wantedMissing:{}},\n  unlocked:['croissant','cinnamon_bun','muffin','baguette','eclair','espresso','cappuccino','latte','lemonade'],\n  decor:{},totalStats:{croissants:0,maxDay:0,repDays:0,day5:false,exps:0,eclairs:0,lattes:0},\n  autoSell:false,dayEarned:0,goals:[],dayOpen:false,dayDone:false,goalsRewarded:false,\n  prevWantedMissing:{},\n};\nlet budgetUsed=0,dayPaused=false;\n\n// ─── AUDIO ─────────────────────────────────────────────────\nlet aCtx;\nfunction ac(){if(!aCtx)aCtx=new(window.AudioContext||window.webkitAudioContext)();return aCtx;}\nfunction tone(f,t='sine',d=.15,v=.25){try{const c=ac(),o=c.createOscillator(),g=c.createGain();o.connect(g);g.connect(c.destination);o.type=t;o.frequency.value=f;g.gain.setValueAtTime(v,c.currentTime);g.gain.exponentialRampToValueAtTime(.001,c.currentTime+d);o.start();o.stop(c.currentTime+d);}catch(e){}}\nfunction ding(){tone(880);setTimeout(()=>tone(1100,'sine',.1),80);}\nfunction boop(){tone(220,'sawtooth',.2,.2);}\nfunction brew(){[300,320,310,330].forEach((f,i)=>setTimeout(()=>tone(f,'sine',.1,.12),i*110));}\nfunction fanfare(){[440,550,660,880].forEach((f,i)=>setTimeout(()=>tone(f,'sine',.2,.28),i*140));}\n\n// ─── SAVE/LOAD ─────────────────────────────────────────────\nasync function save(){\n  const p=JSON.stringify(S);\n  localStorage.setItem('lf',p);\n  try{await fetch('/api/save',{method:'POST',headers:{'Content-Type':'application/json'},body:p});}catch(e){}\n}\nasync function load(){\n  try{const r=await fetch('/api/load');if(r.ok){const d=await r.json();if(d&&d.day){Object.assign(S,d);return;}}}catch(e){}\n  const s=localStorage.getItem('lf');if(s){try{Object.assign(S,JSON.parse(s));}catch(e){}}\n}\n\n// ─── NOTIFY ────────────────────────────────────────────────\nfunction notify(msg,t='i'){\n  const w=document.getElementById('nw'),el=document.createElement('div');\n  el.className=`notif ${t}`;el.textContent=msg;w.appendChild(el);\n  setTimeout(()=>{el.classList.add('out');setTimeout(()=>el.remove(),320);},2600);\n}\n\n// ─── SVG ICONS ─────────────────────────────────────────────\nfunction ingIcon(id,size=28){\n  const icons={\n    flour:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"8\" y=\"10\" width=\"16\" height=\"14\" rx=\"2\" fill=\"#f5deb3\" stroke=\"#d4b080\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"10\" rx=\"8\" ry=\"4\" fill=\"#e8c87a\"/><line x1=\"12\" y1=\"14\" x2=\"20\" y2=\"14\" stroke=\"#d4b080\" stroke-width=\"1\"/><line x1=\"12\" y1=\"18\" x2=\"20\" y2=\"18\" stroke=\"#d4b080\" stroke-width=\"1\"/></svg>`,\n    butter:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"6\" y=\"12\" width=\"20\" height=\"10\" rx=\"3\" fill=\"#ffd700\" stroke=\"#e6b800\" stroke-width=\"1.5\"/><rect x=\"6\" y=\"12\" width=\"20\" height=\"4\" rx=\"3\" fill=\"#ffe566\"/></svg>`,\n    milk:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M11 8 L9 24 Q9 26 16 26 Q23 26 23 24 L21 8Z\" fill=\"#e8f4f8\" stroke=\"#b0d0e0\" stroke-width=\"1.5\"/><path d=\"M10 8 L12 5 H20 L22 8Z\" fill=\"#c8e8f0\"/></svg>`,\n    sugar:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"9\" y=\"11\" width=\"14\" height=\"13\" rx=\"2\" fill=\"#fff8dc\" stroke=\"#e8d890\" stroke-width=\"1.5\"/><circle cx=\"13\" cy=\"16\" r=\"1.5\" fill=\"#fff\"/><circle cx=\"16\" cy=\"14\" r=\"1\" fill=\"#fff\"/><circle cx=\"19\" cy=\"17\" r=\"1.5\" fill=\"#fff\"/></svg>`,\n    cinnamon:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"12\" y=\"6\" width=\"8\" height=\"20\" rx=\"4\" fill=\"#8b4513\" stroke=\"#6b3010\" stroke-width=\"1\"/><path d=\"M14 10 Q18 12 14 16 Q18 18 14 22\" fill=\"none\" stroke=\"#a0522d\" stroke-width=\"1\"/></svg>`,\n    eggs:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"17\" rx=\"7\" ry=\"9\" fill=\"#ffa040\" stroke=\"#e08030\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"17\" rx=\"4\" ry=\"5\" fill=\"#ffe0a0\"/></svg>`,\n    blueberry:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><circle cx=\"16\" cy=\"16\" r=\"9\" fill=\"#6a0dad\" stroke=\"#500a9a\" stroke-width=\"1.5\"/><circle cx=\"13\" cy=\"13\" r=\"3\" fill=\"#8b2fd4\"/><circle cx=\"19\" cy=\"14\" r=\"2.5\" fill=\"#7a1ac0\"/><circle cx=\"15\" cy=\"19\" r=\"3\" fill=\"#7a1ac0\"/></svg>`,\n    water:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M16 6 Q22 14 22 19 A6 6 0 0 1 10 19 Q10 14 16 6Z\" fill=\"#87ceeb\" stroke=\"#5aabce\" stroke-width=\"1.5\"/></svg>`,\n    yeast:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"8\" y=\"10\" width=\"16\" height=\"12\" rx=\"3\" fill=\"#d4b483\" stroke=\"#b09060\" stroke-width=\"1.5\"/><circle cx=\"12\" cy=\"14\" r=\"2\" fill=\"#e8c87a\"/><circle cx=\"16\" cy=\"17\" r=\"2.5\" fill=\"#e8c87a\"/><circle cx=\"20\" cy=\"14\" r=\"1.5\" fill=\"#e8c87a\"/></svg>`,\n    chocolate:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"6\" y=\"9\" width=\"20\" height=\"14\" rx=\"3\" fill=\"#3d1c00\" stroke=\"#2a1200\" stroke-width=\"1.5\"/><line x1=\"6\" y1=\"14\" x2=\"26\" y2=\"14\" stroke=\"#5c3317\" stroke-width=\"1.5\"/><line x1=\"16\" y1=\"9\" x2=\"16\" y2=\"23\" stroke=\"#5c3317\" stroke-width=\"1.5\"/></svg>`,\n    coffee:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"20\" rx=\"8\" ry=\"6\" fill=\"#4a2000\"/><ellipse cx=\"16\" cy=\"18\" rx=\"8\" ry=\"4\" fill=\"#6b3010\"/><path d=\"M13 10 Q13 6 15 8 Q17 6 17 10\" fill=\"none\" stroke=\"#aaa\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    foam:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"18\" rx=\"10\" ry=\"5\" fill=\"#fffaf0\" stroke=\"#e8e0d0\" stroke-width=\"1\"/><circle cx=\"11\" cy=\"17\" r=\"3\" fill=\"#fff\"/><circle cx=\"16\" cy=\"15\" r=\"4\" fill=\"#fff\"/><circle cx=\"21\" cy=\"17\" r=\"3\" fill=\"#fff\"/></svg>`,\n    lemon:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"16\" rx=\"10\" ry=\"8\" fill=\"#ffe066\" stroke=\"#e6c800\" stroke-width=\"1.5\"/><circle cx=\"16\" cy=\"16\" r=\"4\" fill=\"#fff8a0\"/></svg>`,\n    cream:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M10 12 L8 26 Q8 28 16 28 Q24 28 24 26 L22 12Z\" fill=\"#fffcf0\" stroke=\"#dcd4bc\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"12\" rx=\"7\" ry=\"3\" fill=\"#f0e8d8\"/><path d=\"M13 8 Q16 5 19 8\" fill=\"none\" stroke=\"#dcd4bc\" stroke-width=\"1.5\" stroke-linecap=\"round\"/></svg>`,\n    vanilla:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M14 4 Q16 3 18 4 L17 28 Q16 29 15 28Z\" fill=\"#f5e6a0\" stroke=\"#d4c060\" stroke-width=\"1.5\"/><line x1=\"13.5\" y1=\"11\" x2=\"18.5\" y2=\"13\" stroke=\"#c8a840\" stroke-width=\"1\"/><line x1=\"13.5\" y1=\"17\" x2=\"18.5\" y2=\"19\" stroke=\"#c8a840\" stroke-width=\"1\"/></svg>`,\n    honey:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M12 10 L10 26 Q10 28 16 28 Q22 28 22 26 L20 10Z\" fill=\"#ff9800\" stroke=\"#e65100\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"10\" rx=\"7\" ry=\"3\" fill=\"#ffc107\"/><ellipse cx=\"16\" cy=\"19\" rx=\"3\" ry=\"2\" fill=\"#e65100\" opacity=\".4\"/></svg>`,\n    matcha:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"8\" y=\"10\" width=\"16\" height=\"14\" rx=\"2\" fill=\"#4a7c59\" stroke=\"#3d6b4a\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"10\" rx=\"8\" ry=\"4\" fill=\"#5a9c6a\"/><line x1=\"12\" y1=\"14\" x2=\"20\" y2=\"14\" stroke=\"#3d6b4a\" stroke-width=\"1\"/><line x1=\"12\" y1=\"18\" x2=\"20\" y2=\"18\" stroke=\"#3d6b4a\" stroke-width=\"1\"/></svg>`,\n  };\n  return icons[id]||`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><circle cx=\"16\" cy=\"16\" r=\"10\" fill=\"#ccc\"/></svg>`;\n}\n\nfunction recipeIcon(id,size=36){\n  const icons={\n    croissant:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M8 32 C10 16 20 8 34 10 C30 18 18 24 8 32Z\" fill=\"#f4c777\" stroke=\"#c8873a\" stroke-width=\"2\"/><path d=\"M10 30 C13 18 22 12 30 12\" fill=\"none\" stroke=\"#e8a850\" stroke-width=\"1.5\" stroke-linecap=\"round\"/></svg>`,\n    cinnamon_bun:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><circle cx=\"20\" cy=\"20\" r=\"13\" fill=\"#c8873a\"/><path d=\"M12 20 Q16 12 20 20 Q24 28 28 20\" fill=\"none\" stroke=\"#8b4513\" stroke-width=\"2.5\" stroke-linecap=\"round\"/></svg>`,\n    muffin:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"12\" y=\"20\" width=\"16\" height=\"14\" rx=\"3\" fill=\"#c8873a\"/><ellipse cx=\"20\" cy=\"20\" rx=\"10\" ry=\"6\" fill=\"#d4956a\"/><circle cx=\"16\" cy=\"23\" r=\"2.5\" fill=\"#4b0082\"/><circle cx=\"22\" cy=\"27\" r=\"2.5\" fill=\"#4b0082\"/></svg>`,\n    baguette:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><ellipse cx=\"20\" cy=\"20\" rx=\"15\" ry=\"6\" fill=\"#e8c87a\" transform=\"rotate(-25 20 20)\" stroke=\"#c89840\" stroke-width=\"1.5\"/><line x1=\"14\" y1=\"14\" x2=\"22\" y2=\"26\" stroke=\"#c89840\" stroke-width=\"1.5\"/><line x1=\"18\" y1=\"12\" x2=\"26\" y2=\"24\" stroke=\"#c89840\" stroke-width=\"1\"/></svg>`,\n    eclair:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"6\" y=\"14\" width=\"28\" height=\"14\" rx=\"7\" fill=\"#d4956a\"/><rect x=\"6\" y=\"14\" width=\"28\" height=\"7\" rx=\"7\" fill=\"#2c1000\"/></svg>`,\n    espresso:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M13 17 L27 17 L25 32 L15 32Z\" fill=\"#5c3317\"/><ellipse cx=\"20\" cy=\"17\" rx=\"7\" ry=\"3\" fill=\"#3d1c00\"/><path d=\"M15 10 Q15 5 17 8 Q19 5 19 10\" fill=\"none\" stroke=\"#aaa\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    cappuccino:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M10 18 L30 18 L28 33 L12 33Z\" fill=\"#c4956a\"/><ellipse cx=\"20\" cy=\"18\" rx=\"10\" ry=\"4\" fill=\"#fff8f0\"/><circle cx=\"16\" cy=\"17\" r=\"3\" fill=\"#fff\"/><circle cx=\"22\" cy=\"16\" r=\"3.5\" fill=\"#fff\"/><circle cx=\"24\" cy=\"19\" r=\"2.5\" fill=\"#fff\"/></svg>`,\n    latte:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"9\" y=\"16\" width=\"22\" height=\"18\" rx=\"4\" fill=\"#d4a87a\"/><ellipse cx=\"20\" cy=\"16\" rx=\"11\" ry=\"4\" fill=\"#fff8f0\"/><path d=\"M14 15 Q20 12 26 15\" fill=\"none\" stroke=\"rgba(200,135,58,0.5)\" stroke-width=\"1.5\"/></svg>`,\n    lemonade:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"11\" y=\"12\" width=\"18\" height=\"22\" rx=\"4\" fill=\"#fff8aa\" stroke=\"#e8d800\" stroke-width=\"1.5\"/><ellipse cx=\"20\" cy=\"12\" rx=\"9\" ry=\"3\" fill=\"#ffe066\"/><circle cx=\"16\" cy=\"20\" r=\"3\" fill=\"#ffe066\" opacity=\".8\"/><circle cx=\"22\" cy=\"17\" r=\"2.5\" fill=\"#ffe066\" opacity=\".8\"/><line x1=\"24\" y1=\"8\" x2=\"24\" y2=\"14\" stroke=\"#4a7c59\" stroke-width=\"2.5\" stroke-linecap=\"round\"/></svg>`,\n    almond_croissant:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M8 32 C10 16 20 8 34 10 C30 18 18 24 8 32Z\" fill=\"#e8c87a\" stroke=\"#c8873a\" stroke-width=\"2\"/><ellipse cx=\"20\" cy=\"18\" rx=\"5\" ry=\"2\" fill=\"#fff\" opacity=\".6\"/><ellipse cx=\"16\" cy=\"22\" rx=\"3\" ry=\"1.5\" fill=\"#fff\" opacity=\".5\"/></svg>`,\n    honey_cake:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"7\" y=\"22\" width=\"26\" height=\"12\" rx=\"3\" fill=\"#c8873a\"/><rect x=\"7\" y=\"14\" width=\"26\" height=\"10\" rx=\"3\" fill=\"#e8c87a\"/><path d=\"M14 14 Q14 8 20 11 Q26 8 26 14\" fill=\"#ffd700\"/></svg>`,\n    chocolate_croissant:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M8 32 C10 16 20 8 34 10 C30 18 18 24 8 32Z\" fill=\"#f4c777\" stroke=\"#c8873a\" stroke-width=\"2\"/><path d=\"M12 26 C15 20 22 16 28 15\" fill=\"none\" stroke=\"#3d1c00\" stroke-width=\"3\" stroke-linecap=\"round\"/></svg>`,\n    waffle:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"6\" y=\"10\" width=\"28\" height=\"22\" rx=\"4\" fill=\"#e8c87a\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><line x1=\"6\" y1=\"17\" x2=\"34\" y2=\"17\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><line x1=\"6\" y1=\"24\" x2=\"34\" y2=\"24\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><line x1=\"13\" y1=\"10\" x2=\"13\" y2=\"32\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><line x1=\"20\" y1=\"10\" x2=\"20\" y2=\"32\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><line x1=\"27\" y1=\"10\" x2=\"27\" y2=\"32\" stroke=\"#c8a040\" stroke-width=\"1.5\"/></svg>`,\n    tart:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><ellipse cx=\"20\" cy=\"24\" rx=\"14\" ry=\"10\" fill=\"#e8c87a\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><ellipse cx=\"20\" cy=\"20\" rx=\"14\" ry=\"10\" fill=\"#f5deb3\" stroke=\"#c8a040\" stroke-width=\"1.5\"/><circle cx=\"17\" cy=\"18\" r=\"3\" fill=\"#c0392b\"/><circle cx=\"23\" cy=\"19\" r=\"3\" fill=\"#c0392b\"/><circle cx=\"20\" cy=\"24\" r=\"3\" fill=\"#c0392b\"/></svg>`,\n    cheesecake:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M6 30 L20 10 L34 30Z\" fill=\"#fffcf0\" stroke=\"#dcd4bc\" stroke-width=\"2\"/><path d=\"M6 30 L20 10 L34 30\" fill=\"none\" stroke=\"#e8c87a\" stroke-width=\"1.5\"/><path d=\"M8 30 L20 12 L32 30\" fill=\"rgba(200,135,58,.15)\"/></svg>`,\n    matcha_latte:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"9\" y=\"16\" width=\"22\" height=\"18\" rx=\"4\" fill=\"#4a7c59\"/><ellipse cx=\"20\" cy=\"16\" rx=\"11\" ry=\"4\" fill=\"#fff8f0\"/><circle cx=\"16\" cy=\"15\" r=\"3\" fill=\"#fff\"/><circle cx=\"23\" cy=\"14\" r=\"3.5\" fill=\"#fff\"/></svg>`,\n    honey_latte:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"9\" y=\"16\" width=\"22\" height=\"18\" rx=\"4\" fill=\"#d4a87a\"/><ellipse cx=\"20\" cy=\"16\" rx=\"11\" ry=\"4\" fill=\"#ffd700\"/><path d=\"M20 10 Q22 14 20 16\" fill=\"none\" stroke=\"#e65100\" stroke-width=\"2\" stroke-linecap=\"round\"/></svg>`,\n    hot_chocolate:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M10 18 L30 18 L28 33 L12 33Z\" fill=\"#3d1c00\"/><ellipse cx=\"20\" cy=\"18\" rx=\"10\" ry=\"4\" fill=\"#6b3010\"/><circle cx=\"16\" cy=\"17\" r=\"3\" fill=\"#fff\" opacity=\".3\"/><circle cx=\"23\" cy=\"17\" r=\"3.5\" fill=\"#fff\" opacity=\".3\"/></svg>`,\n    vanilla_latte:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"9\" y=\"16\" width=\"22\" height=\"18\" rx=\"4\" fill=\"#d4a87a\"/><ellipse cx=\"20\" cy=\"16\" rx=\"11\" ry=\"4\" fill=\"#fff8f0\"/><path d=\"M16 14 Q20 11 24 14\" fill=\"none\" stroke=\"#f5e6a0\" stroke-width=\"2\" stroke-linecap=\"round\"/></svg>`,\n    recipe_of_day:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><polygon points=\"20,4 23,15 35,15 25,22 29,33 20,26 11,33 15,22 5,15 17,15\" fill=\"#9b59b6\" stroke=\"#7d3c98\" stroke-width=\"1\"/></svg>`,\n    breakfast:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"5\" y=\"10\" width=\"30\" height=\"22\" rx=\"4\" fill=\"#e8c87a\" stroke=\"#c8873a\" stroke-width=\"2\"/><line x1=\"5\" y1=\"18\" x2=\"35\" y2=\"18\" stroke=\"#c8873a\" stroke-width=\"2\"/><line x1=\"18\" y1=\"10\" x2=\"18\" y2=\"32\" stroke=\"#c8873a\" stroke-width=\"2\"/><circle cx=\"11\" cy=\"24\" r=\"4\" fill=\"#ffa040\"/></svg>`,\n  };\n  return icons[id]||`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><circle cx=\"20\" cy=\"20\" r=\"14\" fill=\"#ccc\"/></svg>`;\n}\n\n// ─── HEADER ────────────────────────────────────────────────\nfunction updateHdr(){\n  document.getElementById('hdr-day').textContent=`День ${S.day} · ${DAYS[(S.day-1)%7]}`;\n  document.getElementById('hdr-wx').textContent=`${S.weather.icon} ${S.weather.name}`;\n  document.getElementById('hdr-money').textContent=`${S.money} ₽`;\n  document.getElementById('rep-pct').textContent=`${Math.round(S.rep)}%`;\n  document.getElementById('rep-fill').style.width=`${Math.min(100,S.rep)}%`;\n}\n\n// ─── TOOLBAR ───────────────────────────────────────────────\nfunction updateToolbar(){\n  const r=document.getElementById('tb-r');\n  if(!S.dayOpen&&!S.dayDone){\n    r.innerHTML=`<button class=\"btn btn-p\" style=\"font-size:12px;padding:7px 16px\" onclick=\"openBakery()\">☀️ Открыть кофейню</button>`;\n  } else if(S.dayOpen&&!S.dayDone){\n    const pauseLbl=dayPaused?'▶ Продолжить':'⏸ Пауза';\n    const pauseStyle=dayPaused?'background:var(--sage);color:#fff':'';\n    r.innerHTML=`<button class=\"btn btn-o\" id=\"btn-pause\" style=\"font-size:12px;padding:7px 13px;${pauseStyle}\" onclick=\"togglePause()\">${pauseLbl}</button>\n    <button class=\"btn\" style=\"background:var(--espresso);color:var(--cream);font-size:12px;padding:7px 13px\" onclick=\"endDay()\">🌙 Закрыть день</button>`;\n  } else {\n    r.innerHTML=`<button class=\"btn btn-p\" style=\"font-size:12px;padding:7px 16px\" onclick=\"nextDay()\">Следующий день →</button>`;\n  }\n}\n\n// ─── MORNING / WORKBENCH ───────────────────────────────────\nfunction pickGoals(){\n  const pool=[...GOAL_POOL];\n  const easy=pool.filter(g=>g.reward<=80),hard=pool.filter(g=>g.reward>80);\n  const picks=[];\n  for(let i=0;i<2&&easy.length;i++){const j=Math.floor(Math.random()*easy.length);picks.push(easy.splice(j,1)[0]);}\n  for(let i=picks.length;i<3&&hard.length;i++){const j=Math.floor(Math.random()*hard.length);picks.push(hard.splice(j,1)[0]);}\n  S.goals=picks;\n}\n\nfunction renderGoals(){\n  const sec=document.getElementById('goals-sec'),list=document.getElementById('goals-list');\n  if(!S.goals||!S.goals.length){sec.style.display='none';return;}\n  sec.style.display='block';list.innerHTML='';\n  S.goals.forEach(g=>{\n    const done=S.dayDone&&g.check&&g.check();\n    const el=document.createElement('div');el.className='goal-item';\n    el.innerHTML=`<span class=\"goal-chk\">${done?'✅':'🎯'}</span><span class=\"goal-desc\">${g.desc}</span><span class=\"goal-rwd\">+${g.reward}₽</span>`;\n    list.appendChild(el);\n  });\n}\n\nfunction renderDemand(){\n  const sec=document.getElementById('demand-sec'),list=document.getElementById('demand-list');\n  const wm=S.prevWantedMissing||{};\n  const items=Object.entries(wm).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]);\n  if(!items.length){sec.style.display='none';return;}\n  sec.style.display='block';list.innerHTML='';\n  items.forEach(([id,cnt])=>{\n    const r=RECIPES.find(x=>x.id===id);if(!r)return;\n    const tag=document.createElement('span');tag.className='demand-tag';\n    tag.textContent=`${r.name} ×${cnt}`;list.appendChild(tag);\n  });\n}\n\nfunction renderWorkbench(){\n  renderIngs();renderSidebar();updateBudget();renderGoals();renderDemand();\n  // show/hide open button\n  document.getElementById('open-btn-wrap').style.display=S.dayOpen?'none':'block';\n}\n\nfunction renderIngs(){\n  const l=document.getElementById('ing-list');l.innerHTML='';\n  INGS.forEach(ing=>{\n    const d=document.createElement('div');d.className='ing-item';d.draggable=true;d.dataset.id=ing.id;\n    d.innerHTML=ingIcon(ing.id,22)+`<span>${ing.name}</span>`;\n    d.addEventListener('dragstart',e=>{e.dataTransfer.setData('text/plain',ing.id);d.style.opacity='.4';});\n    d.addEventListener('dragend',()=>d.style.opacity='1');\n    d.addEventListener('click',()=>{if(S.table.length<5){S.table.push(ing.id);brew();renderTable();checkMatch();}else notify('Максимум 5 ингредиентов','b');});\n    l.appendChild(d);\n  });\n}\n\nconst dz=document.getElementById('drop-zone');\ndz.addEventListener('dragover',e=>{e.preventDefault();dz.classList.add('over');});\ndz.addEventListener('dragleave',()=>dz.classList.remove('over'));\ndz.addEventListener('drop',e=>{\n  e.preventDefault();dz.classList.remove('over');\n  const id=e.dataTransfer.getData('text/plain');\n  if(id&&S.table.length<5){S.table.push(id);brew();renderTable();checkMatch();}\n});\n\nfunction renderTable(){\n  const hint=document.getElementById('drop-hint');\n  dz.querySelectorAll('.di').forEach(x=>x.remove());\n  hint.style.display=S.table.length?'none':'flex';\n  S.table.forEach((id,i)=>{\n    const ing=INGS.find(x=>x.id===id);if(!ing)return;\n    const el=document.createElement('div');el.className='di';\n    el.innerHTML=ingIcon(id,24)+`<span>${ing.name}</span>`;\n    el.title='Кликните чтобы убрать';\n    el.onclick=()=>{S.table.splice(i,1);renderTable();checkMatch();};\n    dz.appendChild(el);\n  });\n}\n\nfunction checkMatch(){\n  const res=document.getElementById('rm-res'),exp=document.getElementById('exp-hint');\n  const sorted=[...S.table].sort();\n  if(!sorted.length){res.innerHTML='<span style=\"opacity:.4\">Пока ничего...</span>';exp.style.display='none';return;}\n  let m=null;\n  for(const r of RECIPES){\n    if(!S.unlocked.includes(r.id))continue;\n    if(JSON.stringify([...r.ings].sort())===JSON.stringify(sorted)){m=r;break;}\n  }\n  if(m){res.innerHTML=`<div class=\"rm-card\">${recipeIcon(m.id,26)}<strong>${m.name}</strong><span>${m.price} ₽</span></div>`;exp.style.display='none';return;}\n  for(const r of RECIPES){\n    if(S.unlocked.includes(r.id))continue;\n    if(JSON.stringify([...r.ings].sort())===JSON.stringify(sorted)){\n      res.innerHTML=`<div class=\"rm-card\" style=\"background:#888;opacity:.85\">${recipeIcon(r.id,26)}<strong>🔒 ${r.name}</strong><span>Нужно разблокировать</span></div>`;\n      exp.style.display='none';return;\n    }\n  }\n  if(sorted.length>=2){res.innerHTML='<span style=\"color:rgba(28,10,0,.45);font-size:12px\">Неизвестная комбинация</span>';exp.style.display='block';}\n  else{res.innerHTML='<span style=\"opacity:.4\">Добавьте ещё...</span>';exp.style.display='none';}\n}\n\nfunction clearTable(){S.table=[];renderTable();checkMatch();}\n\nfunction tryExp(){\n  if(S.table.length<2){notify('Нужно минимум 2 ингредиента!','b');return;}\n  S.dayStats.exp++;S.totalStats.exps++;\n  if(Math.random()>.4){\n    const lu=RECIPES.filter(r=>!S.unlocked.includes(r.id))[0];\n    fanfare();\n    if(lu&&Math.random()>.5){S.unlocked.push(lu.id);notify(`Открыт рецепт: ${lu.name}!`,'g');}\n    else{notify('Эксперимент удался! +50₽','g');S.money+=50;updateHdr();}\n  }else{boop();notify('Эксперимент не удался...','b');}\n  clearTable();save();\n}\n\nfunction addToShowcase(){\n  const sorted=[...S.table].sort();\n  if(!sorted.length){notify('Стол пуст!','b');return;}\n  let m=null;\n  for(const r of RECIPES){\n    if(!S.unlocked.includes(r.id))continue;\n    if(JSON.stringify([...r.ings].sort())===JSON.stringify(sorted)){m=r;break;}\n  }\n  if(!m){notify('Рецепт не распознан. Попробуйте эксперимент!','i');return;}\n  const total=Object.values(S.showcase).reduce((a,b)=>a+b,0);\n  if(total>=20){notify('Витрина полна!','b');return;}\n  const cost=Math.round(m.price*.3);\n  if(S.money<cost){notify('Недостаточно денег!','b');return;}\n  S.showcase[m.id]=(S.showcase[m.id]||0)+1;\n  S.money-=cost;budgetUsed+=cost;\n  clearTable();renderSidebar();updateBudget();updateHdr();ding();\n  notify(`${m.name} → витрина`,'g');\n}\n\nfunction renderSidebar(){\n  const l=document.getElementById('sc-list'),e=document.getElementById('sc-empty');\n  l.innerHTML='';\n  const items=Object.keys(S.showcase).filter(k=>S.showcase[k]>0);\n  e.style.display=items.length?'none':'block';\n  items.forEach(id=>{\n    const r=RECIPES.find(x=>x.id===id);if(!r)return;\n    const d=document.createElement('div');d.className='sc-item';\n    d.innerHTML=`${recipeIcon(id,22)}<span class=\"iname\">${r.name}</span><span class=\"iprice\">${r.price}₽</span>\n    <div class=\"qty\"><button class=\"qb\" onclick=\"chQty('${id}',-1)\">−</button><span class=\"qv\">${S.showcase[id]}</span><button class=\"qb\" onclick=\"chQty('${id}',1)\">+</button></div>`;\n    l.appendChild(d);\n  });\n  document.getElementById('cap-used').textContent=Object.values(S.showcase).reduce((a,b)=>a+b,0);\n}\n\nfunction chQty(id,d){\n  const r=RECIPES.find(x=>x.id===id),c=Math.round(r.price*.3),n=(S.showcase[id]||0)+d;\n  if(n<=0){delete S.showcase[id];}\n  else if(n>20){notify('Максимум 20','b');return;}\n  else{\n    if(d>0){if(S.money<c){notify('Недостаточно денег!','b');return;}S.money-=c;budgetUsed+=c;}\n    else{S.money+=c;budgetUsed-=c;}\n    S.showcase[id]=n;\n  }\n  renderSidebar();updateBudget();updateHdr();\n}\n\nfunction updateBudget(){\n  document.getElementById('bleft').textContent=`${S.money} ₽`;\n  document.getElementById('bfill').style.width=`${Math.min(100,budgetUsed/(500+(S.day-1)*100)*100)}%`;\n}\n\nfunction openBakery(){\n  if(!Object.keys(S.showcase).length){notify('Витрина пуста — приготовьте что-нибудь!','b');return;}\n  S.dayStats={earned:0,sold:{},unhappy:0,exp:0,byType:{},wantedMissing:{}};S.dayEarned=0;\n  S.dayOpen=true;S.dayDone=false;S.goalsRewarded=false;\n  dayPaused=false;\n  document.getElementById('open-btn-wrap').style.display='none';\n  document.getElementById('day-card').style.display='block';\n  document.getElementById('evening-card').style.display='none';\n  updateToolbar();\n  initDay();\n}\n\n// ─── RECIPE BOOK ───────────────────────────────────────────\nfunction openRB(){\n  ['bakery','drinks','special'].forEach(t=>document.getElementById(`rb-${t}`).innerHTML='');\n  const spec=RECIPES.filter(r=>r.cat==='special');\n  document.getElementById('rb-special-hdr').style.display=spec.length?'block':'none';\n  RECIPES.forEach(r=>{\n    const unlk=S.unlocked.includes(r.id);\n    const el=document.createElement('div');el.className=`rb-card ${unlk?'unlocked':'locked'}`;\n    const ings=r.ings.map(i=>{const x=INGS.find(g=>g.id===i);return x?x.name:'?';}).join(' + ')||'???';\n    el.innerHTML=`${recipeIcon(r.id,34)}<div class=\"rc-name\">${unlk?r.name:'???'}</div><div class=\"rc-price\">${unlk?r.price+'₽':'🔒'}</div><div class=\"rc-ings\">${unlk?ings:'Неизвестно'}</div>`;\n    const target=r.cat==='bakery'?'rb-bakery':r.cat==='drink'?'rb-drinks':'rb-special';\n    document.getElementById(target).appendChild(el);\n  });\n  document.getElementById('rb-overlay').classList.add('active');\n}\nfunction closeRB(){document.getElementById('rb-overlay').classList.remove('active');}\n\n// ─── DECOR MODAL ───────────────────────────────────────────\nfunction openDecor(){\n  renderDecor();\n  document.getElementById('decor-overlay').classList.add('active');\n}\nfunction closeDecor(){document.getElementById('decor-overlay').classList.remove('active');}\n\n// ─── DAY PHASE ─────────────────────────────────────────────\nconst DAY_DURATION=8*60;\nconst MAX_SEATS=6;\nconst seatOccupied={};\nlet custs=[],queue=[],dayRunning=false,dayTime=0,lastSpawn=0,nextSpawnIn=10;\nlet activeCust=null,animId=null;\n\nclass Cust{\n  constructor(){\n    const w=[3,2,3,2,3,1];let roll=Math.random()*14,acc=0,idx=0;\n    for(let i=0;i<w.length;i++){acc+=w[i];if(roll<acc){idx=i;break;}}\n    this.type=CTYPES[idx];\n    if(this.type.prefs){\n      const prefs=this.type.prefs.filter(id=>S.unlocked.includes(id));\n      this.want=prefs.length?prefs[Math.floor(Math.random()*prefs.length)]:S.unlocked[Math.floor(Math.random()*S.unlocked.length)];\n    }else{\n      this.want=S.unlocked[Math.floor(Math.random()*S.unlocked.length)];\n    }\n    this.state='waiting';\n    this.patience=this.type.patience*(S.decor['jazz']?1.3:1);\n    this.waitTime=0;this.id=Math.random();\n    this.seatIdx=-1;this.eatTime=0;this.eatDur=10+Math.random()*10;\n  }\n  wantName(){const r=RECIPES.find(x=>x.id===this.want);return r?r.name:'что-нибудь';}\n}\n\nfunction initDay(){\n  custs=[];queue=[];dayRunning=true;dayTime=0;lastSpawn=0;\n  nextSpawnIn=5+Math.random()*4;activeCust=null;\n  Object.keys(seatOccupied).forEach(k=>delete seatOccupied[k]);\n  document.getElementById('day-earned-hdr').textContent='0 ₽';\n  document.getElementById('day-log-line').textContent='';\n  renderCafeDecorRow();\n  updateQueueDisplay();\n  setTimeout(spawnCust,1500);\n  if(animId)cancelAnimationFrame(animId);\n  let last=null;\n  function loop(ts){\n    if(!dayRunning)return;\n    if(!last)last=ts;\n    const dt=Math.min((ts-last)/1000,.05);last=ts;\n    if(!dayPaused){\n      dayTime+=dt;lastSpawn+=dt;\n      const pct=Math.min(1,dayTime/DAY_DURATION);\n      const gMin=Math.floor((dayTime%60)/60*60);\n      const gHour=8+Math.floor(dayTime/60);\n      document.getElementById('time-lbl').textContent=`${gHour}:${String(gMin).padStart(2,'0')}`;\n      document.getElementById('day-timebar').style.width=(pct*100)+'%';\n      if(dayTime>=DAY_DURATION){notify('Рабочий день окончен!','i');endDay();return;}\n      // Spawn\n      if(lastSpawn>=nextSpawnIn&&custs.filter(c=>c.state==='waiting').length<5){\n        spawnCust();\n        if(Math.random()<.2)setTimeout(spawnCust,1800);\n        lastSpawn=0;nextSpawnIn=6+Math.random()*6;\n      }\n      // Update customers\n      custs.forEach(c=>{\n        if(c.state==='waiting'){\n          c.waitTime+=dt;\n          if(c.waitTime>c.patience){leaveAngry(c);}\n        }\n        if(c.state==='eating'){\n          c.eatTime+=dt;\n          if(c.eatTime>=c.eatDur){seatOccupied[c.seatIdx]=false;c.state='gone';}\n        }\n      });\n      custs=custs.filter(c=>c.state!=='gone');\n      queue=queue.filter(c=>c.state==='waiting');\n      // Auto-sell\n      if(S.autoSell&&queue.length){\n        const f=queue[0];\n        if(f&&f.want&&S.showcase[f.want]>0){activeCust=f;setTimeout(()=>{if(activeCust===f)doSell();},200);}\n      }\n      if(!activeCust&&queue.length){activeCust=queue[0];updateCustUI();}\n      else if(!queue.length&&!activeCust){document.getElementById('cafe-active-cust').textContent='Ждём гостей...';}\n      updateQueueDisplay();\n    }\n    animId=requestAnimationFrame(loop);\n  }\n  animId=requestAnimationFrame(loop);\n}\n\nfunction spawnCust(){\n  const c=new Cust();custs.push(c);queue.push(c);\n  addLog(`${c.type.emoji} ${c.type.name} → хочет ${c.wantName()}`);\n}\n\nfunction leaveAngry(c){\n  S.rep=Math.max(0,S.rep-2);S.dayStats.unhappy++;\n  addLog(`😤 ${c.type.name} ушёл недовольным!`,'b');\n  queue=queue.filter(x=>x!==c);c.state='gone';\n  if(activeCust===c){activeCust=null;if(queue.length){activeCust=queue[0];updateCustUI();}else document.getElementById('cafe-active-cust').textContent='Ждём гостей...';}\n  updateQueueDisplay();updateHdr();boop();\n}\n\nfunction updateCustUI(){\n  if(!activeCust)return;\n  const avail=(S.showcase[activeCust.want]||0)>0;\n  const clr=avail?'var(--sage)':'var(--red)';\n  const sfx=avail?'':`&nbsp;<span style=\"color:var(--red)\">❌ нет в наличии</span>`;\n  document.getElementById('cafe-active-cust').innerHTML=`${activeCust.type.emoji} <b>${activeCust.type.name}</b> хочет: <span style=\"color:${clr};font-weight:700\">${recipeIcon(activeCust.want,16)} ${activeCust.wantName()}</span>${sfx}`;\n}\n\nfunction updateQueueDisplay(){\n  const el=document.getElementById('queue-display');if(!el)return;\n  el.innerHTML='';\n  document.getElementById('queue-lbl').style.display=queue.length?'inline':'none';\n  queue.slice(0,5).forEach(c=>{\n    const pct=Math.max(0,1-c.waitTime/c.patience);\n    const div=document.createElement('div');div.className='q-av'+(pct<.3?' angry':'');\n    div.title=`${c.type.name}: ${c.wantName()}`;\n    div.innerHTML=`<div class=\"qf\">${c.type.emoji}</div><div class=\"qb\" style=\"--p:${Math.round(pct*100)}%\"></div>`;\n    el.appendChild(div);\n  });\n  const eating=custs.filter(c=>c.state==='eating').length;\n  document.getElementById('eating-info').textContent=eating?`🍽 ${eating} едят`:'';\n  renderSeats();\n}\n\nfunction renderSeats(){\n  const el=document.getElementById('cafe-seats');if(!el)return;\n  el.innerHTML='';\n  for(let i=0;i<MAX_SEATS;i++){\n    const c=custs.find(x=>x.state==='eating'&&x.seatIdx===i);\n    const div=document.createElement('div');\n    div.className='seat-slot'+(c?' occupied':'');\n    if(c){\n      const pct=Math.round(Math.min(1,c.eatTime/c.eatDur)*100);\n      div.title=`${c.type.name} ест`;\n      div.innerHTML=`${c.type.emoji}<div class=\"seat-bar\" style=\"--p:${pct}%\"></div>`;\n    }else{\n      div.textContent='🪑';div.style.opacity='.4';\n    }\n    el.appendChild(div);\n  }\n}\n\nfunction renderCafeDecorRow(){\n  const el=document.getElementById('cafe-decor-row');if(!el)return;\n  const map={painting:'🖼',plant:'🪴',lighting:'💡',jazz:'🎵',menu_board:'📋',table:'🟫'};\n  el.innerHTML=Object.keys(map).filter(k=>S.decor[k]).map(k=>map[k]).join(' ');\n}\n\nfunction addLog(msg,cls=''){\n  const el=document.getElementById('day-log-line');if(!el)return;\n  el.textContent=msg;\n  el.style.color=cls==='b'?'rgba(255,100,80,.8)':cls==='g'?'rgba(100,200,120,.9)':'rgba(245,230,200,.65)';\n}\n\nfunction sellToCust(){\n  if(!activeCust||activeCust.state!=='waiting'){notify('Нет клиента у стойки','b');return;}\n  doSell();\n}\n\nfunction doSell(){\n  const c=activeCust;\n  const r=RECIPES.find(x=>x.id===c.want);\n  if(!r||!S.showcase[c.want]||S.showcase[c.want]<=0){\n    if(c.want)S.dayStats.wantedMissing[c.want]=(S.dayStats.wantedMissing[c.want]||0)+1;\n    notify(`${c.type.name} расстроен — нет ${c.wantName()}!`,'b');\n    rejectCust();return;\n  }\n  S.showcase[c.want]--;\n  const tip=Math.round(r.price*c.type.tip),earned=r.price+tip;\n  S.money+=earned;S.dayEarned+=earned;S.dayStats.earned+=earned;\n  S.dayStats.sold[c.want]=(S.dayStats.sold[c.want]||0)+1;\n  if(!S.dayStats.byType)S.dayStats.byType={};\n  S.dayStats.byType[c.type.id]=(S.dayStats.byType[c.type.id]||0)+1;\n  S.totalStats.croissants+=(c.want==='croissant'?1:0);\n  S.totalStats.eclairs+=(c.want==='eclair'?1:0);\n  S.totalStats.lattes+=(c.want==='latte'?1:0);\n  // seat customer\n  const si=Array.from({length:MAX_SEATS},(_,i)=>i).find(i=>!seatOccupied[i]);\n  if(si!=null){seatOccupied[si]=true;c.seatIdx=si;c.state='eating';c.eatTime=0;}\n  else{c.state='gone';}\n  queue=queue.filter(x=>x!==c);activeCust=null;\n  document.getElementById('day-earned-hdr').textContent=`${S.dayEarned} ₽`;\n  addLog(`+${earned}₽ — ${r.name}${tip>0?` (+${tip}₽ чаев.)`:''}`, 'g');\n  updateHdr();renderSidebar();ding();\n  if(queue.length){activeCust=queue[0];updateCustUI();}\n  else document.getElementById('cafe-active-cust').textContent='Ждём гостей...';\n  save();\n}\n\nfunction rejectCust(){\n  if(!activeCust)return;\n  const c=activeCust;c.state='gone';\n  S.rep=Math.max(0,S.rep-1);\n  queue=queue.filter(x=>x!==c);activeCust=null;\n  addLog(`${c.type.emoji} ${c.type.name} ушёл без покупки`);updateHdr();\n  if(queue.length){activeCust=queue[0];updateCustUI();}\n  else document.getElementById('cafe-active-cust').textContent='Ждём гостей...';\n}\n\nfunction toggleAuto(){\n  S.autoSell=!S.autoSell;\n  const b=document.getElementById('btn-auto');\n  b.textContent=`🤖 Авто: ${S.autoSell?'ВКЛ':'ВЫКЛ'}`;\n  b.style.background=S.autoSell?'var(--caramel)':'';\n  b.style.color=S.autoSell?'#fff':'';\n}\n\nfunction togglePause(){\n  dayPaused=!dayPaused;\n  updateToolbar();\n  notify(dayPaused?'⏸ Пауза':'▶ Продолжаем!','i');\n}\n\n// ─── END DAY ───────────────────────────────────────────────\nfunction endDay(){\n  if(!dayRunning)return;\n  dayRunning=false;if(animId)cancelAnimationFrame(animId);\n  custs=[];queue=[];Object.keys(seatOccupied).forEach(k=>delete seatOccupied[k]);\n  if(S.dayEarned>S.totalStats.maxDay)S.totalStats.maxDay=S.dayEarned;\n  if(S.rep>=80)S.totalStats.repDays++;\n  if(S.day>=3)S.totalStats.day5=true;\n  const sold=Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0);\n  if(sold>10)S.rep=Math.min(100,S.rep+3);\n  if(S.dayStats.unhappy>3)S.rep=Math.max(0,S.rep-3);\n  if(S.decor['plant'])S.rep=Math.min(100,S.rep+2);\n  S.dayDone=true;\n  dayPaused=false;\n  document.getElementById('day-card').style.display='none';\n  updateToolbar();\n  checkUnlocks();\n  renderEveningCard();\n  save();\n}\n\n// ─── EVENING CARD ──────────────────────────────────────────\nfunction renderEveningCard(){\n  const card=document.getElementById('evening-card');\n  card.style.display='block';\n  const ts=Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0);\n  // Goals\n  let goalsHtml='',bonus=0;\n  if(S.goals&&S.goals.length){\n    S.goals.forEach(g=>{\n      const done=g.check&&g.check();\n      if(done)bonus+=g.reward;\n      goalsHtml+=`<div class=\"ev-goal${done?' done':''}\"><span>${done?'✅':'❌'}</span><span style=\"flex:1\">${g.desc}</span><span>${done?'+'+g.reward+'₽':'—'}</span></div>`;\n    });\n    if(bonus>0&&!S.goalsRewarded){S.goalsRewarded=true;S.money+=bonus;updateHdr();}\n  }\n  // Leftovers\n  let lftHtml='';\n  const lftItems=Object.keys(S.showcase).filter(k=>S.showcase[k]>0);\n  if(lftItems.length){\n    lftHtml=lftItems.map(id=>{const r=RECIPES.find(x=>x.id===id);return`<span class=\"ev-lft-tag\">${r?r.name:id} ×${S.showcase[id]}</span>`;}).join('');\n  }\n  // Sales bars\n  const sorted=Object.entries(S.dayStats.sold).sort((a,b)=>b[1]-a[1]);\n  const mx=sorted[0]?sorted[0][1]:1;\n  const barsHtml=sorted.slice(0,5).map(([id,cnt])=>{\n    const r=RECIPES.find(x=>x.id===id);\n    return`<div style=\"display:flex;align-items:center;gap:7px;margin-bottom:4px\">\n      <span style=\"font-size:11px;width:120px;font-weight:600\">${r?r.name:id}</span>\n      <div style=\"flex:1;height:12px;background:rgba(28,10,0,.08);border-radius:6px;overflow:hidden\"><div style=\"height:100%;background:var(--caramel);border-radius:6px;width:${cnt/mx*100}%\"></div></div>\n      <span style=\"font-size:11px;font-weight:700;color:var(--caramel)\">${cnt}</span>\n    </div>`;\n  }).join('');\n  card.innerHTML=`\n    <div style=\"display:flex;align-items:center;gap:12px;margin-bottom:10px\">\n      <div style=\"font-family:'Playfair Display',serif;font-size:18px;font-weight:700\">День ${S.day} завершён!</div>\n      <div class=\"ev-stats\" style=\"margin:0\">\n        <div class=\"ev-stat\"><div class=\"ev-v\">${S.dayStats.earned}₽</div><div class=\"ev-l\">Выручка</div></div>\n        <div class=\"ev-stat\"><div class=\"ev-v\">${ts}</div><div class=\"ev-l\">Продано</div></div>\n        <div class=\"ev-stat\"><div class=\"ev-v\">${Math.round(S.rep)}%</div><div class=\"ev-l\">Репутация</div></div>\n      </div>\n    </div>\n    ${barsHtml?`<div style=\"margin-bottom:8px\">${barsHtml}</div>`:''}\n    ${goalsHtml?`<div class=\"ev-goals\">${goalsHtml}</div>`:''}\n    ${bonus>0?`<div class=\"ev-bonus\">🎉 Бонус за цели: +${bonus}₽</div>`:''}\n    ${lftHtml?`<div class=\"ev-leftovers\"><span style=\"font-size:11px;font-weight:600\">Остатки:</span>${lftHtml}\n      <button class=\"btn btn-s\" style=\"font-size:11px;padding:4px 10px\" onclick=\"sellLeftovers()\">Продать −50%</button>\n      <button class=\"btn btn-o\" style=\"font-size:11px;padding:4px 10px\" onclick=\"throwLeftovers()\">Выбросить</button>\n    </div>`:'<div style=\"font-size:12px;color:var(--sage);font-weight:600;margin-bottom:8px\">✨ Всё продано!</div>'}\n    <div id=\"unlock-area\"></div>\n  `;\n}\n\nfunction checkUnlocks(){\n  let unlock=null;\n  if(S.totalStats.croissants>=20&&!S.unlocked.includes('almond_croissant'))\n    unlock={id:'almond_croissant',desc:'Продал 20 круассанов!'};\n  else if(S.dayStats.earned>=1000&&!S.unlocked.includes('honey_cake'))\n    unlock={id:'honey_cake',desc:'1000₽ за день!'};\n  else if(S.totalStats.exps>=1&&!S.unlocked.includes('recipe_of_day'))\n    unlock={id:'recipe_of_day',desc:'Первый удачный эксперимент!'};\n  else if(S.totalStats.day5&&!S.unlocked.includes('matcha_latte'))\n    unlock={id:'matcha_latte',desc:'3 дня в деле!'};\n  else if(S.totalStats.repDays>=3&&!S.unlocked.includes('breakfast'))\n    unlock={id:'breakfast',desc:'Репутация 80%+ три дня!'};\n  else if(S.totalStats.eclairs>=10&&!S.unlocked.includes('chocolate_croissant'))\n    unlock={id:'chocolate_croissant',desc:'Продал 10 эклеров!'};\n  else if(S.day>=5&&!S.unlocked.includes('waffle'))\n    unlock={id:'waffle',desc:'5 дней работы!'};\n  else if(S.totalStats.maxDay>=2000&&!S.unlocked.includes('tart'))\n    unlock={id:'tart',desc:'2000₽ за один день!'};\n  else if(S.totalStats.lattes>=15&&!S.unlocked.includes('honey_latte'))\n    unlock={id:'honey_latte',desc:'Продал 15 латте!'};\n  else if(S.totalStats.maxDay>=3000&&!S.unlocked.includes('hot_chocolate'))\n    unlock={id:'hot_chocolate',desc:'3000₽ за один день!'};\n  else if(S.day>=8&&!S.unlocked.includes('vanilla_latte'))\n    unlock={id:'vanilla_latte',desc:'8-й день работы!'};\n  else if(S.dayStats.earned>=1500&&!S.unlocked.includes('cheesecake'))\n    unlock={id:'cheesecake',desc:'1500₽ за день!'};\n  if(unlock){\n    S.unlocked.push(unlock.id);\n    const r=RECIPES.find(x=>x.id===unlock.id);\n    setTimeout(()=>{\n      const a=document.getElementById('unlock-area');\n      if(a)a.innerHTML=`<div class=\"ev-unlock\">🎉 Новый рецепт разблокирован: <strong>${r?r.name:unlock.id}</strong> — ${unlock.desc}</div>`;\n    },500);\n    fanfare();save();\n  }\n}\n\nfunction sellLeftovers(){\n  let e=0;\n  Object.keys(S.showcase).forEach(id=>{const r=RECIPES.find(x=>x.id===id),q=S.showcase[id]||0;if(q&&r)e+=Math.round(r.price*.5)*q;});\n  S.money+=e;S.showcase={};notify(`Продано остатков на ${e}₽`,'g');updateHdr();renderEveningCard();\n}\nfunction throwLeftovers(){S.showcase={};notify('Остатки выброшены','i');renderEveningCard();}\n\nfunction nextDay(){\n  S.day++;S.weather=WEATHERS[Math.floor(Math.random()*WEATHERS.length)];\n  S.showcase={};budgetUsed=0;\n  S.prevWantedMissing={...(S.dayStats.wantedMissing||{})};\n  S.dayStats={earned:0,sold:{},unhappy:0,exp:0,byType:{},wantedMissing:{}};\n  S.dayEarned=0;S.dayOpen=false;S.dayDone=false;S.goalsRewarded=false;\n  S.goals=[];pickGoals();\n  document.getElementById('evening-card').style.display='none';\n  document.getElementById('day-card').style.display='none';\n  document.getElementById('open-btn-wrap').style.display='block';\n  updateToolbar();updateHdr();save();\n  renderWorkbench();\n  S.money+=50;updateHdr();\n  notify(`День ${S.day} начинается! +50₽ на утро`,'g');\n}\n\n// ─── DECOR ────────────────────────────────────────────────\nfunction renderDecor(){\n  drawDecorPreview();\n  const l=document.getElementById('decor-list');l.innerHTML='';\n  DECORS.forEach(item=>{\n    const owned=!!S.decor[item.id];\n    const d=document.createElement('div');d.className='di-item';\n    d.innerHTML=`<div class=\"dico\">${item.icon}</div>\n    <div class=\"dinfo\"><div class=\"dtitle\">${item.name}</div><div class=\"ddesc\">${item.desc}</div></div>\n    ${owned?'<span class=\"owned-badge\">Куплено</span>':`<div style=\"text-align:right\"><div class=\"dprice\">${item.price}₽</div><button class=\"btn btn-p\" style=\"font-size:11px;padding:4px 9px;margin-top:3px\" onclick=\"buyDecor('${item.id}')\">Купить</button></div>`}`;\n    l.appendChild(d);\n  });\n}\n\nfunction drawDecorPreview(){\n  const dc=document.getElementById('dc'),dctx=dc.getContext('2d'),W=dc.width,H=dc.height;\n  dctx.clearRect(0,0,W,H);\n  const wg=dctx.createLinearGradient(0,0,0,H*.6);\n  wg.addColorStop(0,'#fdf0d8');wg.addColorStop(1,'#f0dfc0');\n  dctx.fillStyle=wg;dctx.fillRect(0,0,W,H*.6);\n  const fg=dctx.createLinearGradient(0,H*.6,0,H);\n  fg.addColorStop(0,'#d8c4a0');fg.addColorStop(1,'#c8b48a');\n  dctx.fillStyle=fg;dctx.fillRect(0,H*.6,W,H*.4);\n  dctx.strokeStyle='rgba(180,150,100,.3)';dctx.lineWidth=1;\n  for(let x=0;x<W;x+=60){dctx.beginPath();dctx.moveTo(x,H*.6);dctx.lineTo(x,H);dctx.stroke();}\n  for(let y=H*.6;y<H;y+=40){dctx.beginPath();dctx.moveTo(0,y);dctx.lineTo(W,y);dctx.stroke();}\n  dctx.fillStyle='#a07040';dctx.fillRect(0,H*.6,W,7);\n  [[60,25],[270,25]].forEach(([x,y])=>{\n    dctx.fillStyle='#8b5e3c';dctx.fillRect(x,y,80,75);\n    dctx.fillStyle='rgba(135,200,235,.65)';dctx.fillRect(x+4,y+4,72,67);\n    dctx.strokeStyle='rgba(255,255,255,.4)';dctx.lineWidth=1.5;\n    dctx.beginPath();dctx.moveTo(x+40,y+4);dctx.lineTo(x+40,y+71);dctx.stroke();\n    dctx.beginPath();dctx.moveTo(x+4,y+38);dctx.lineTo(x+76,y+38);dctx.stroke();\n    dctx.fillStyle='#a07040';dctx.fillRect(x-4,y+75,88,7);\n  });\n  if(S.decor['painting'])drawPainting(dctx,160,20);\n  if(S.decor['plant'])drawPlant(dctx,W-55,H*.55);\n  if(S.decor['menu_board']){dctx.fillStyle='#2c3e50';dctx.fillRect(390,22,100,78);dctx.strokeStyle='#c8873a';dctx.lineWidth=2;dctx.strokeRect(390,22,100,78);}\n  if(S.decor['lighting']){\n    const lg=dctx.createRadialGradient(W/2,0,5,W/2,0,W*.7);\n    lg.addColorStop(0,'rgba(255,220,100,.2)');lg.addColorStop(1,'rgba(255,220,100,0)');\n    dctx.fillStyle=lg;dctx.fillRect(0,0,W,H);\n  }\n  if(S.decor['jazz']){dctx.font='18px serif';dctx.fillStyle='rgba(142,68,173,.55)';dctx.fillText('♪',W-32,55);dctx.fillText('♫',W-55,40);}\n  if(S.decor['table']){\n    [[100,H*.62],[230,H*.62],[360,H*.62]].forEach(([tx,ty])=>{\n      dctx.fillStyle='#a07040';dctx.beginPath();dctx.ellipse(tx,ty,36,12,0,0,Math.PI*2);dctx.fill();\n      dctx.strokeStyle='#8b5e3c';dctx.lineWidth=1.5;dctx.beginPath();dctx.ellipse(tx,ty,36,12,0,0,Math.PI*2);dctx.stroke();\n      dctx.fillStyle='#8b5e3c';dctx.fillRect(tx-4,ty+10,7,H-ty-10);\n    });\n  }\n  dctx.fillStyle='#6b3a1a';dctx.fillRect(W-150,H*.58,150,H*.42);\n  dctx.fillStyle='#a07040';dctx.fillRect(W-155,H*.55,158,14);\n}\n\nfunction drawPainting(ctx,x,y){\n  ctx.fillStyle='#8b5e3c';ctx.fillRect(x,y,95,70);\n  const pg=ctx.createLinearGradient(x+5,y+5,x+90,y+65);\n  pg.addColorStop(0,'#87ceeb');pg.addColorStop(1,'#6aade4');\n  ctx.fillStyle=pg;ctx.fillRect(x+5,y+5,85,60);\n  ctx.fillStyle='#4a7c59';ctx.beginPath();ctx.arc(x+28,y+42,14,0,Math.PI*2);ctx.fill();\n  ctx.fillStyle='#c8873a';ctx.beginPath();ctx.arc(x+58,y+33,11,0,Math.PI*2);ctx.fill();\n  ctx.strokeStyle='#8b5e3c';ctx.lineWidth=4;ctx.strokeRect(x,y,95,70);\n}\n\nfunction drawMenuBoard(ctx,x,y){\n  ctx.fillStyle='#2c3e50';ctx.fillRect(x,y,120,85);\n  ctx.strokeStyle='#c8873a';ctx.lineWidth=3;ctx.strokeRect(x,y,120,85);\n  ctx.fillStyle='#f5e6c8';ctx.font='bold 12px Nunito,sans-serif';ctx.textAlign='center';\n  ctx.fillText('МЕНЮ ДНЯ',x+60,y+20);\n  ctx.font='10px Nunito,sans-serif';ctx.fillStyle='rgba(245,230,200,.75)';\n  ['Круассан 80₽','Латте 150₽','Эклер 120₽'].forEach((t,i)=>ctx.fillText(t,x+60,y+36+i*14));\n}\n\nfunction drawPlant(ctx,x,y){\n  [[0,-18,16],[- 11,-7,12],[11,-10,11]].forEach(([dx,dy,r])=>{\n    ctx.fillStyle='#4a7c59';ctx.beginPath();ctx.arc(x+dx,y+dy,r,Math.PI,0);ctx.fill();\n  });\n  ctx.fillStyle='#8b5e3c';ctx.fillRect(x-9,y,18,24);\n  ctx.fillStyle='#a07040';ctx.fillRect(x-11,y-2,22,5);\n}\n\nfunction buyDecor(id){\n  const item=DECORS.find(x=>x.id===id);if(!item)return;\n  if(S.decor[id]){notify('Уже куплено','i');return;}\n  if(S.money<item.price){notify(`Нужно ${item.price}₽`,'b');return;}\n  S.money-=item.price;S.decor[id]=true;\n  notify(`${item.name} добавлен!`,'g');fanfare();updateHdr();save();\n  renderDecor();\n}\n\n// ─── INIT ──────────────────────────────────────────────────\nasync function init(){\n  await load();\n  if(!S.goals)S.goals=[];\n  if(!S.prevWantedMissing)S.prevWantedMissing={};\n  if(!S.dayStats.byType)S.dayStats.byType={};\n  if(!S.dayStats.wantedMissing)S.dayStats.wantedMissing={};\n  if(!S.totalStats.eclairs)S.totalStats.eclairs=0;\n  if(!S.totalStats.lattes)S.totalStats.lattes=0;\n  if(S.goals.length===0)pickGoals();\n  // If we were in the middle of a day, reset to morning state\n  if(S.dayOpen&&!S.dayDone){\n    S.dayOpen=false;\n    S.dayStats={earned:0,sold:{},unhappy:0,exp:0,byType:{},wantedMissing:{}};\n  }\n  updateHdr();updateToolbar();\n  renderWorkbench();\n}\ninit();\n</script>\n</body>\n</html>\n";

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', ...CORS },
  });
}

function userKey(request) {
  const ip = request.headers.get('CF-Connecting-IP') || 'anonymous';
  return `save:${ip}`;
}

async function handleSave(request, env) {
  const contentLength = parseInt(request.headers.get('Content-Length') || '0', 10);
  if (contentLength > MAX_PAYLOAD) return json({ error: 'Payload too large' }, 413);

  let body;
  try {
    body = await request.text();
    JSON.parse(body);
  } catch {
    return json({ error: 'Invalid JSON' }, 400);
  }

  const key = userKey(request);
  await env.LAFOURNEE_KV.put(key, body, { expirationTtl: 60 * 60 * 24 * 365 });
  return json({ ok: true });
}

async function handleLoad(request, env) {
  const key = userKey(request);
  const value = await env.LAFOURNEE_KV.get(key, 'text');
  if (!value) return json({ ok: false, error: 'No save found' }, 404);

  try {
    return json(JSON.parse(value));
  } catch {
    return json({ error: 'Corrupted save' }, 500);
  }
}

export default {
  async fetch(request, env) {
    const { method, pathname } = Object.assign(
      { method: request.method },
      { pathname: new URL(request.url).pathname }
    );

    if (method === 'OPTIONS') return new Response(null, { status: 204, headers: CORS });

    if (pathname === '/api/save' && method === 'POST') return handleSave(request, env);
    if (pathname === '/api/load' && method === 'GET')  return handleLoad(request, env);

    // Serve game for any other GET (/ or unknown paths)
    if (method === 'GET') {
      return new Response(GAME_HTML, {
        headers: {
          'Content-Type': 'text/html; charset=utf-8',
          'Cache-Control': 'public, max-age=60',
        },
      });
    }

    return new Response('Not Found', { status: 404 });
  },
};
